const feed = $json;
const topPackage = Array.isArray(feed?.top_packages) && feed.top_packages.length ? feed.top_packages[0] : null;
const packagePrice = Number(topPackage?.price || 1000);
const bankRate = 4;
const zagRate = Number(topPackage?.monthly_return_rate_percent || 0);
const bankYearValue = Number((packagePrice * (1 + (bankRate / 100))).toFixed(2));
const bankYearGain = Number((bankYearValue - packagePrice).toFixed(2));
const zagMonthEstimate = Number((packagePrice * (zagRate / 100)).toFixed(2));

const prompt = `You are creating premium short-form marketing content for ZagChain.

Theme: bank vs ZagChain.
Use only the facts in the input JSON and the comparison figures provided below.
Do not promise guaranteed returns.
Do not say risk-free.
Do not use fake urgency.
Output must be valid JSON.

Comparison frame:
- Example amount: $${packagePrice}
- Example bank annual rate: ${bankRate}%
- Example bank yearly value: $${bankYearValue}
- Example bank yearly gain: $${bankYearGain}
- ZagChain example package: ${topPackage?.name || 'ZagChain package'}
- ZagChain displayed monthly rate example: ${zagRate}%
- ZagChain monthly estimate example: $${zagMonthEstimate}

Return a JSON object with exactly these keys:
instagram_caption, tiktok_hook, video_script_15s, video_script_30s, story_text, image_headline, image_subheadline, cta, hashtags, canva_image_brief, canva_video_brief

Rules:
- hashtags must be an array of 5 hashtags
- keep it persuasive, clear, premium, and simple
- focus on the difference between sleeping savings and smarter earnings visibility
- make the comparison understandable for normal users
- avoid legal or financial overclaiming

Input JSON:
${JSON.stringify(feed, null, 2)}`;

return [{
  feed,
  ai_prompt: prompt,
  comparison: {
    example_amount_usd: packagePrice,
    bank_annual_rate_percent: bankRate,
    bank_yearly_value_usd: bankYearValue,
    bank_yearly_gain_usd: bankYearGain,
    zag_package_name: topPackage?.name || 'ZagChain package',
    zag_monthly_rate_percent: zagRate,
    zag_monthly_estimate_usd: zagMonthEstimate
  }
}];

