const raw = $json.output_text || '';
let content = {};

try {
  content = raw ? JSON.parse(raw) : {};
} catch (error) {
  content = {
    instagram_caption: raw,
    tiktok_hook: '',
    video_script_15s: '',
    video_script_30s: '',
    story_text: '',
    image_headline: '',
    image_subheadline: '',
    cta: '',
    hashtags: [],
    canva_image_brief: '',
    canva_video_brief: '',
    parse_error: 'OpenAI response was not valid JSON. Review raw output manually.'
  };
}

const hashtags = Array.isArray(content.hashtags) ? content.hashtags.join(' ') : String(content.hashtags || '');
const preview = `zagn8n bank vs ZagChain ready\n\nHook: ${content.tiktok_hook || ''}\n\nHeadline: ${content.image_headline || ''}\n\nCTA: ${content.cta || ''}\n\nHashtags: ${hashtags}`;

return [{
  ...content,
  preview_message: preview,
  raw_output_text: raw,
  hashtags_text: hashtags,
  generated_at: new Date().toISOString()
}];
